namespace sv_4ac81e73520d49eea8b5c9b5276a2310.Services;

public class WarehouseStateService
{
    private string _currentWarehouseId = "WH-001";

    public event Action? OnChange;

    public string CurrentWarehouseId
    {
        get => _currentWarehouseId;
        set
        {
            if (_currentWarehouseId != value)
            {
                _currentWarehouseId = value;
                NotifyStateChanged();
            }
        }
    }

    public string CurrentWarehouseName =>
        Warehouses.FirstOrDefault(w => w.Id == _currentWarehouseId)?.Name ?? "Unknown";

    public IReadOnlyList<Warehouse> Warehouses { get; } =
    [
        new("WH-001", "Warehouse A - Downtown"),
        new("WH-002", "Warehouse B - Airport"),
        new("WH-003", "Warehouse C - Harbor"),
        new("WH-004", "Warehouse D - Industrial Park")
    ];

    private void NotifyStateChanged() => OnChange?.Invoke();
}

public record Warehouse(string Id, string Name);

namespace sv_4ac81e73520d49eea8b5c9b5276a2310.Services;

public class InventoryAlertService
{
    private readonly Random _random = new();

    /// <summary>
    /// Fired when new alert data has been fetched. All subscribed components should re-render.
    /// </summary>
    public event Action? OnAlertDataChanged;

    public int LatestLowStockCount { get; private set; }

    /// <summary>
    /// Simulates a database query returning the number of items below minimum stock levels.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async DB call with random result 0-15
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Called by the polling component after fetching new data.
    /// Stores the latest count and notifies all subscribers.
    /// </summary>
    public void PublishUpdate(int lowStockCount)
    {
        LatestLowStockCount = lowStockCount;
        OnAlertDataChanged?.Invoke();
    }
}

