@using sv_4ac81e73520d49eea8b5c9b5276a2310.Services
@rendermode InteractiveServer
@inject WarehouseStateService WarehouseState
@implements IDisposable

<div class="warehouse-selector d-flex align-items-center gap-2">
    <label class="form-label mb-0 text-nowrap fw-semibold">Site:</label>
    <select class="form-select form-select-sm" @bind="SelectedWarehouseId">
        @foreach (var wh in WarehouseState.Warehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private string SelectedWarehouseId
    {
        get => WarehouseState.CurrentWarehouseId;
        set => WarehouseState.CurrentWarehouseId = value;
    }

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@using sv_4ac81e73520d49eea8b5c9b5276a2310.Services
@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@inject WarehouseStateService WarehouseState
@implements IDisposable

<span class="alert-badge position-relative">
    <span class="bi bi-exclamation-triangle-fill-nav-menu" aria-hidden="true"></span>
    @if (AlertService.LatestLowStockCount > 0)
    {
        <span class="badge bg-danger rounded-pill">@AlertService.LatestLowStockCount</span>
    }
    else
    {
        <span class="badge bg-success rounded-pill">0</span>
    }
</span>

@code {
    protected override void OnInitialized()
    {
        AlertService.OnAlertDataChanged += OnAlertChanged;
        WarehouseState.OnChange += OnAlertChanged;
    }

    private void OnAlertChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertDataChanged -= OnAlertChanged;
        WarehouseState.OnChange -= OnAlertChanged;
    }
}

@page "/dashboard"
@using sv_4ac81e73520d49eea8b5c9b5276a2310.Services
@rendermode InteractiveServer
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard - @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="text-muted">Currently viewing: <strong>@WarehouseState.CurrentWarehouseName</strong></p>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card @(lowStockCount > 5 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="display-4 @(lowStockCount > 5 ? "text-danger" : "text-success")">
                    @lowStockCount
                </p>
                <p class="text-muted">items below minimum level</p>
                @if (isPolling)
                {
                    <small class="text-muted">
                        <span class="spinner-border spinner-border-sm me-1"></span>
                        Polling every 10s
                    </small>
                }
            </div>
        </div>
    </div>
    <div class="col-md-8">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Activity Log</h5>
                <ul class="list-group list-group-flush" style="max-height: 300px; overflow-y: auto;">
                    @foreach (var entry in activityLog)
                    {
                        <li class="list-group-item">@entry</li>
                    }
                </ul>
            </div>
        </div>
    </div>
</div>

@code {
    private int lowStockCount;
    private bool isPolling;
    private CancellationTokenSource? _cts;
    private List<string> activityLog = new();

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        AlertService.OnAlertDataChanged += OnAlertDataChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await FetchAlerts();
            StartPolling();
        }
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        isPolling = true;
        _ = PollLoopAsync(_cts.Token);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
