+            while (await timer.WaitForNextTickAsync(ct))
+            {
+                await FetchAlerts();
+            }
+        }
+        catch (OperationCanceledException) { }
+    }
+
+    private async Task FetchAlerts()
+    {
+        var count = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
+        lowStockCount = count;
+
+        activityLog.Insert(0,
+            $"[{DateTime.Now:HH:mm:ss}] Checked {WarehouseState.CurrentWarehouseName}: {count} low-stock items");
+        if (activityLog.Count > 20)
+            activityLog.RemoveAt(activityLog.Count - 1);
+
+        // Publish so sidebar badge and other subscribers update
+        AlertService.PublishUpdate(count);
+        await InvokeAsync(StateHasChanged);
+    }
+
+    private async void OnWarehouseChanged()
+    {
+        // Immediately re-fetch when warehouse changes
+        await FetchAlerts();
+    }
+
+    private void OnAlertDataChanged()
+    {
+        lowStockCount = AlertService.LatestLowStockCount;
+        InvokeAsync(StateHasChanged);
+    }
+
+    public void Dispose()
+    {
+        StopPolling();
+        WarehouseState.OnChange -= OnWarehouseChanged;
+        AlertService.OnAlertDataChanged -= OnAlertDataChanged;
+    }
+}
+

